class Solution:
    def minCost(self, nums, x):
        n = len(nums)
        ans = None
        for K in range(n):
            total = K * x
            for t in range(n):
                best = min(nums[(t - k) % n] for k in range(K + 1))
                total += best
            if ans is None or total < ans:
                ans = total
        return ans

