class Solution:
    def minCost(self, nums, x):
        n = len(nums)
        best = list(nums)
        total = sum(best)
        ans = total
        for k in range(1, n):
            s = 0
            for t in range(n):
                idx = (t - k) % n
                if nums[idx] < best[t]:
                    best[t] = nums[idx]
                s += best[t]
            cost = s + k * x
            if cost < ans:
                ans = cost
        return ans

