var minCost = function(nums, x) {
    const n = nums.length;
    const best = nums.slice();
    let total = best.reduce((a, b) => a + b, 0);
    let ans = total;
    for (let k = 1; k < n; k++) {
        let s = 0;
        for (let t = 0; t < n; t++) {
            const idx = ((t - k) % n + n) % n;
            if (nums[idx] < best[t]) best[t] = nums[idx];
            s += best[t];
        }
        const cost = s + k * x;
        if (cost < ans) ans = cost;
    }
    return ans;
};
